// PROP-022 phase 5: verifier becomes archive-aware for files that have an archive sibling.
// SCAN_TARGETS gains an optional 4th tuple member: archive_path (or null).
// const SCAN_TARGETS = [
//   ['monitor/decisions/closed-issues.json',     'issues', 'id', 'monitor/decisions/closed-issues-archive.jsonl'],   // phase 6
//   ['monitor/analyst/expansion-tracker.json',   'items',  'id', 'monitor/analyst/expansion-tracker-archive.jsonl'], // phase 5
// ];

const archivePath = arguments[3] || null;  // 4th arg of processFile
const toArchive = [];  // entries to append-and-remove from live

for (const entry of arr) {
  const status = entry.status || '';
  if (!PENDING_SUFFIX_RE.test(status)) continue;
  perFile.checked++;

  const v = verifyEntry(entry);
  const id = entry[idField] || entry.win_id || '<no-id>';

  if (v.decision === 'flip') {
    perFile.flipped++;
    summary.flipped_entries.push({
      file: filePath, id, from: status, to: v.terminal, primitive: v.primitive,
    });
    if (!DRY_RUN) {
      entry.status = v.terminal;
      entry.verified_at = NOW_ISO;
      entry.verified_by_run = RUN_ID;
      entry.verifier_script_version = VERSION;
      // PROP-022 phase 5: integrated discriminator carries the truth post-flip
      if (v.terminal === 'integrated' && filePath.endsWith('expansion-tracker.json')) {
        entry.integrated = true;
        entry.integrated_at = entry.integrated_at || NOW_ISO;  // preserve decider-stamped time if present
      }
      mutated = true;
      // Queue for archive-append + live-remove. Do the move at end of loop
      // so we don't mutate the array while iterating it.
      if (archivePath) toArchive.push({entry, idx: arr.indexOf(entry)});
    }
  } else if (v.decision === 'still_pending') {
    // ... unchanged
  } else {
    // ... unchanged
  }
}

// PROP-022 phase 5/6: append-and-remove to archive as part of the same write.
if (archivePath && toArchive.length > 0 && !DRY_RUN) {
  const lines = toArchive.map(t => JSON.stringify(t.entry)).join('\n') + '\n';
  fs.appendFileSync(archivePath, lines);
  // Remove from live: filter out the archived ids in one pass
  const archivedIds = new Set(toArchive.map(t => t.entry[idField]));
  data[arrayKey] = arr.filter(e => !archivedIds.has(e[idField]));
  perFile.archived = toArchive.length;
}

if (mutated && !DRY_RUN) {
  // ... writeFileSync of full live file (now smaller because of archived items)
}
