const id=target.id;
// Apply the new transition pattern
target.integrated=true;
target.integrated_at=new Date().toISOString();
fs.appendFileSync('/tmp/expansion-tracker-archive-test.jsonl',JSON.stringify(target)+'\n');
t.items=t.items.filter(i=>i.id!==id);
